import type { VariantProps } from "class-variance-authority";
import { cva } from "class-variance-authority";

import { cn } from "@acme/ui/lib/utils";

import "./style.css";

import type { DetailedHTMLProps, HTMLAttributes, ReactNode } from "react";

const spinVariants = cva("", {
  variants: {
    size: {
      small: [
        "size-5",
        "before:bg-size-[4px_4px]! after:bg-size-[6px_6px]!",
        "before:m-0.5",
      ],
      default: ["size-7", "before:bg-size-[5px_5px]! after:bg-size-[8px_8px]!"],
      large: [
        "size-12",
        "before:bg-size-[8px_8px]! after:bg-size-[12px_12px]!",
      ],
    },
  },
  defaultVariants: {
    size: "default",
  },
});
export type SpinProps = DetailedHTMLProps<
  HTMLAttributes<HTMLDivElement>,
  HTMLDivElement
> &
  VariantProps<typeof spinVariants> & {
    spinning?: boolean;
    tip?: ReactNode;
  };
export const Spin = ({
  spinning = true,
  tip,
  className,
  size,
  children,
  ...props
}: SpinProps) => {
  return (
    <div className={cn("relative", className)} {...props}>
      {spinning && (
        <div
          key="loading"
          className="absolute inset-0 z-10 flex max-h-[400px] flex-col items-center justify-center"
        >
          <div
            aria-label="Loading"
            className={cn("spin", spinVariants({ size }))}
          />
          {tip && <div className="mt-2">{tip}</div>}
        </div>
      )}
      <div
        className={cn("h-full", spinning && "pointer-events-none opacity-50")}
      >
        {children}
      </div>
    </div>
  );
};

.spin {
  aspect-ratio: 1;
  display: grid;
}
.spin::before,
.spin::after {
  content: "";
  grid-area: 1/1;
  --c: no-repeat
    radial-gradient(farthest-side, var(--color-primary-600) 92%, #0000);
  background:
    var(--c) 50% 0,
    var(--c) 50% 100%,
    var(--c) 100% 50%,
    var(--c) 0 50%;
  animation: l12 1s infinite;
}
.spin::before {
  filter: hue-rotate(45deg);
  animation-timing-function: linear;
}

@keyframes l12 {
  100% {
    transform: rotate(0.5turn);
  }
}
